import React from 'react';
import '../Styles/Global.css';

const AboutUs = () => {
  return (
    <section className="about-us-section">
      <h2 className="about-heading">About Us</h2>
      <div className="about-us-container">
        <div className="about-us-image">
          <img src="/assests/hero.jpg" alt="About Us" />
        </div>
        <div className="about-us-text">
          <p>
            At NatureNest, we believe every space deserves a touch of green. Our mission is to bring nature closer to you — whether indoors or outdoors.
          </p>
          <p>
            With a curated collection of healthy plants, expert tips, and eco-friendly tools, we help you transform your surroundings into a calming and vibrant sanctuary.
          </p>
          <p>
            From rare finds to classic favorites, NatureNest is your trusted partner in growing and nurturing a greener world.
          </p>
        </div>
      </div>
    </section>
  );
};

export default AboutUs;
